test('uses stubbed client', () => {
  const apiStub = { getUser: () => ({ id: 1, name: 'Ada' }) };
  expect(loadProfile(apiStub).name).toBe('Ada');
});

class ApiStub:
    def get_user(self):
        return {'id': 1, 'name': 'Ada'}
api_stub = ApiStub()
profile = load_profile(api_stub)
assert profile['name'] == 'Ada'

public class ApiStub implements ApiClient {
    public User getUser() {
        return new User(1, "Ada");
    }
}

CREATE TABLE stub_users (
    id INT PRIMARY KEY,
    name VARCHAR(255)
);
INSERT INTO stub_users VALUES (1, 'Ada');
